        YOUR_CHOCOBO_WILL_BECOME_MORE_PROACTIVE_WITH_DIGGING                    = 7582,  -- Your chocobo will become more proactive with digging the more you command it to dig!
        I_CALL_THIS_WING_SKILL_WHICH_CAN_INCREASE                               = 7583,  -- I call this "wing skill," which can increase all the way up to level #!
        I_CAN_TELL_YOU_YOUR_WING_SKILL_AT                                       = 7584,  -- I can tell you your wing skill at any time, so feel free to ask.
        YOUR_SUMMONED_CHOCOBO_S_PERSONALITY_AFFECTS_CHOCOBO_DIGGING             = 7585,  -- Your summoned chocobo's personality affects chocobo digging.
        STRONGER_CHOCOBOS_CAN_EARN_MORE_CURRENCY_AND_CHOCOBOS                   = 7586,  -- Stronger chocobos can earn more currency, and chocobos with high durability can dig up more items each day (Earth time).
        SMARTER_CHOCOBOS_SOMETIMES_DON_T_NEED_TO_EAT                            = 7587,  -- Smarter chocobos sometimes don't need to eat gysahl greens, and compassionate chocobos are more likely to find rare items.
        THERE_ARE_ALSO_A_VARIETY_OF_ABILITIES_YOUR                              = 7588,  -- There are also a variety of abilities your chocobos can learn to dig up multiple items at the same time.
        YOUR_WING_SKILL_IS_CURRENTLY                                            = 7589,  -- Your wing skill is currently...#[./!/!!/!!!/!!!!]
        DEBUG_MENU_FOR_MOVE_TIME_FORWARD_SEE_AN                                 = 7590,  -- Debug menu for %%: Move time forward. See an event. Change to default. Naming test. Weather check test (Ronfaure). Confirm chocobo status. Alter chocobo status. User work display. Control status. Control growth stages. Control DNA. Receive item. Control flags. Abilities. Cancel.
        SKIP_EVENTS_AFTER_MOVING_TIME_FORWARD_SKIP_ALL                          = 7591,  -- Skip events after moving time forward? Skip all events. Don't skip events.
