        CHOOSE_YOUR_RANGE_IN_HUNDREDS_000_099_100                               = 7594,  -- Choose your range in hundreds. 000-099. 100-199.00-255. Cancel.
        CHOOSE_YOUR_RANGE_IN_TENS_00_09_10                                      = 7595,  -- Choose your range in tens. 00-09. 10-19.0-29.0-39. 40-49. 50-59. 60-69. 70-79. 80-89. 90-99. Cancel.
        CHOOSE_YOUR_RANGE_TO_THE_SINGLE_DIGIT_0                                 = 7596,  -- Choose your range to the single digit. 0. 1... 4. 5. 6. 7. 8. 9. Cancel.
