        CHOOSE_AN_EVENT_WATCH_OVER_CHOCOBO_FEED_CHOCOBO                         = 7600,  -- Choose an event. Watch over chocobo. Feed chocobo. Tell a story. Scold chocobo. Compete. Go on a walk 1. Go on a walk 2. Go on a walk 3. Cancel.
        CHOOSE_AN_EVENT_INJURY_LIGHT_ILLNESS_STOMACHACHE_LONELINESS             = 7601,  -- Choose an event. Injury. Light illness. Stomachache. Loneliness. Happiness. Laziness. Serious illness. Confusion. Spoiled. Runaway. In love. Crying at night. Injury healed. Light illness healed. Stomachache healed. Loneliness healed. No longer happy. Laziness healed. Serious illness healed. Confusion healed. No longer spoiled. Back from running away. No longer in love. Crying at night healed. Bursting with vitality. No longer bursting with vitality. Sparkling intelligence. No longer sparkling with intelligence.
