        SAKURA_SAYS_THAT_SHE_LOVES_YOU_ALL_FROM                                 = 8740,  -- Sakura says that she loves you all from the bottom of her tiny heart.
        ALRIGHTY_THEN_OUR_NEXT_RACE_FEATURES_OF_VANA                            = 8741,  -- Alrighty then, our next race features # of Vana'diel's top chocobos. Let us start off by introducing the birds and their jockeys.
        FIRST_WE_HAVE_WHO_WILL_BE_RIDDEN_BY                                     = 8742,  -- First we have %, who will be ridden by [the ace of the chase, Ignazio/three-time chocobo racing alltar, Eudocia/the bloody emperor, Roinolier/the empress of speed, Maurette/Lami-Baami Suave Esquire III/the red rose of racing, Sosopapa/CRA legend, Khowa Mathgalhi/rising CRA star, Bayansh].
        S_S_I                                                                   = 8743,  -- s%s%I
        SHE_SAYS_WHEN_THE_ACE_MAKES_CHASE_THERE                                 = 8744,  -- She says, When the ace makes chase, there's not a bird in Vana'diel who can keep pace.
