        I_M_SORRY_SIR_MA_AM_BUT_I                                               = 9465,  -- I'm sorry, sir/ma'am], but I am currently not accepting chocobets.
        WHAT_TOPIC_WOULD_YOU_LIKE_CLARIFICATION_ON_CHOCOBET                     = 9466,  -- What topic would you like clarification on? Chocobet tickets. Winnings. Quit. Return.
        WHEN_PURCHASING_A_CHOCOBET_TICKET_YOU_WILL_BE                           = 9467,  -- When purchasing a chocobet ticket, you will be asked to place a quinella bet. This means that you will choose the two chocobos that you think will place first and second. If you are lucky enough to win, you may then exchange the ticket and collect your winnings.
        IN_OUR_CURRENT_CHOCOBET_SYSTEM_AS_LONG_AS                               = 9468,  -- In our current chocobet system, as long as your two picks finish in the top two, the order doesn't matter.
        THE_SIZE_OF_A_CHOCOBET_TICKET_IS_MEASURED                               = 9469,  -- The size of a chocobet ticket is measured in quills. One quill costs 100 gil, and a single ticket can contain up to 999 quills. Try it once, and you'll get hooked for sure!
        YOU_CAN_STAND_TO_MAKE_QUITE_A_PROFIT                                    = 9470,  -- You can stand to make quite a profit if you buy a chocobet ticket and it hits!
        THE_FEWER_THE_BETTORS_WHO_HAVE_SELECTED_THE                             = 9471,  -- The fewer the bettors who have selected the same chocobos as you, the greater your winnings will be! In the industry, we call those the odds.
        YOU_CAN_ALWAYS_CHECK_THE_CURRENT_ODDS_WHEN                              = 9472,  -- You can always check the current odds when you place a chocobet. However, the odds are always apt to change right up until the chocobet window closes for that race. So be careful!
        TO_COLLECT_YOUR_WINNINGS_SIMPLY_BRING_YOUR_CHOCOBET                     = 9473,  -- To collect your winnings, simply bring your chocobet ticket back to any of us here at the betting center.
        HOWEVER_YOU_SHOULD_KNOW_THAT_A_WINNING_CHOCOBET                         = 9474,  -- However, you should know that a winning chocobet ticket is only valid for one week following completion of the race. After that, it will expire, so be sure to cash it in before then!
        ATTENTION_BETTORS_ONLY_REMAINING_TO_PLACE_YOUR_CHOCOBETS                = 9475,  -- Attention, bettors! Only # [minute/minutes] remaining to place your chocobets!
        ATTENTION_BETTORS_LAST_CALL_LAST_CALL_FOR_CHOCOBETS                     = 9476,  -- Attention, bettors! Last call! Last call for chocobets!
        I_M_SORRY_SIR_MA_AM_BUT_WE                                              = 9477,  -- I'm sorry, sir/ma'am], but we are currently not accepting chocobets.
