        VERY_WELL_FRIEND_SHOULD_YOU_EVER_FIND_YOURSELF                          = 10168,  -- Very well, friend. Should you ever find yourself in need of assistance, do not hesitate to return.
        GREETINGS_FRIEND_I_AM_A_SYNERGY_ENGINEER_DISPATCHED                     = 10169,  -- Greetings, friend! I am a synergy engineer, dispatched from the Institute to maintain the furnaces you see beside me. I also have knowledge and services to share with fellow synergists, if that is what you desire.
        I_SEE_FROM_THE_PUZZLED_EXPRESSION_ON_YOUR                               = 10170,  -- I see from the puzzled expression on your face that you are unfamiliar with our discipline. To use these furnaces, you will first need to obtain %.
        PIQUED_YOUR_CURIOSITY_HAVE_I_THEN_YOU_SHOULD                            = 10171,  -- Piqued your curiosity, have I? Then you should speak with Hildolf, our institute director, at his laboratory in the Bastok Metalworks. He's always eager to welcome a new synergist to our ranks.
        MAY_I_BE_OF_SERVICE_NOT_NOW_LEARN                                       = 10172,  -- May I be of service? Not now. Learn recipes. Check fewell. Replenish fewell. Purchase materials. Receive training. Trade cinder. Get information.
        RECIPES_YOU_SAY_LET_S_SEE_WHAT_WE                                       = 10173,  -- Recipes, you say? Let's see what we have that's suitable for your level of expertise...
        I_M_SORRY_I_M_AFRAID_THERE_S                                            = 10174,  -- ...I'm sorry. I'm afraid there's nothing I can teach you at the moment.
        I_VE_GOT_IT_HOW_ABOUT_MIND_YOU                                          = 10175,  -- I've got it! How about %? Mind you, it'll require a certain level of skill...
